var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"다음 씬은 자신이 준 임무에 실패한 로봇 함장을 파벨라가 추궁하는 장면이야.","JPN":"次のシーンは自分が与えた任務に失敗したロボットの艦長をファヴェーラが追及するシーンだ。","ENG":"The next scene is where Fabella interrogates the robot captain who failed the mission.","TWN":"下一個是機器人艦長沒有完成帕貝拉交付的任務，所以帕貝拉在究責的場景。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"악녀 파벨라의 주먹부터 나가는 성격이 제대로 드러나는 부분이지.","JPN":"悪女ファヴェーラの、先に拳が出る性格がしっかり現われる場面だ。","ENG":"It’s a scene where Fabella’s hot temper really shows.","TWN":"要呈現出惡女 帕貝拉總是用拳頭處理事情的性格。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"자, 액션!","JPN":"レディ、アクション！","ENG":"Ready, action!","TWN":"預備，Action！"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"변명해봐라, 잭.","JPN":"説明しろ、ジャック。","ENG":"Explain to me, Jack.","TWN":"傑克，你給我解釋清楚！"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"왜 프레데리카가 탈출하도록 내버려뒀지?","JPN":"なんでフレデリカの脱出を見逃した？","ENG":"Why did you let Frederica escape?","TWN":"為什麼會讓弗蕾德莉卡給逃掉？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STAFF_NPC_DRAMA_ROBOT","text":{"KOREA":"죄송합니다, 미스 파벨라.","JPN":"申し訳ございません、ミス・ファヴェーラ。","ENG":"I’m sorry, Miss Fabella.","TWN":"很抱歉，帕貝拉小姐。"},"stage":{"bg":"FALL_PARK","slots":{"L":{"char_id":"STAFF_NPC_DRAMA_ROBOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"STAFF_NPC_DRAMA_ROBOT","text":{"KOREA":"그 남성 승무원이 미스 프레데리카를 도와줄 거라는 건 계산하지 못했습니다.","JPN":"あの男性乗務員がミス・フレデリカに協力するとは、計算違いでした。","ENG":"I never thought the steward would help Miss Frederica.","TWN":"我沒計算到那位男空服員會協助弗蕾德莉卡小姐逃跑。"},"stage":{"bg":"FALL_PARK","slots":{"L":{"char_id":"STAFF_NPC_DRAMA_ROBOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"헛소리! 그 남자가 프레데리카를 좋아한다는 걸 몰랐다고 할 셈이야?","JPN":"ふざけるな！　あの男がフレデリカを気にかけていたってことを知らなかったっていうのか？","ENG":"Nonsense! Are you trying to say that you didn’t know the steward likes Frederica?","TWN":"胡扯！你以為說不知道那個男的喜歡弗蕾德莉卡，就可以蒙混過關嗎？"},"stage":{"bg":"FALL_PARK","slots":{"L":{"char_id":"STAFF_NPC_DRAMA_ROBOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"STAFF_NPC_DRAMA_ROBOT","text":{"KOREA":"인간의 사랑이 만들어내는 변수는 무한합니다, 미스 파벨라.","JPN":"人間の愛が作り出す変数は無限です、ミス・ファヴェーラ。","ENG":"The variables that human love creates are infinite, Miss Fabella.","TWN":"帕貝拉小姐，因人類的愛情而產生的變數是無法計算的。"},"stage":{"bg":"FALL_PARK","slots":{"L":{"char_id":"STAFF_NPC_DRAMA_ROBOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"STAFF_NPC_DRAMA_ROBOT","text":{"KOREA":"최신 기종의 오퍼레이터인 저희도 그것만큼은 계산하는 법을 모릅니다.","JPN":"最新機種のオペレーターである私たちでさえも、その計算方法だけは知りません。","ENG":"Even up-to-date operators like us don’t know how to calculate those variables.","TWN":"就算我們是最新型的領航員，也無從計算。"},"stage":{"bg":"FALL_PARK","slots":{"L":{"char_id":"STAFF_NPC_DRAMA_ROBOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"웃기지 마! 넌 함장 실격이야!","JPN":"黙れ！　あんたは艦長失格だ！","ENG":"Stop talking gibberish! You’re disqualified from being captain!","TWN":"開什麼玩笑！你根本沒資格當艦長！"},"stage":{"bg":"FALL_PARK","slots":{"L":{"char_id":"STAFF_NPC_DRAMA_ROBOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"STAFF_NPC_DRAMA_ROBOT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FALL_PARK","slots":{"L":{"char_id":"STAFF_NPC_DRAMA_ROBOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"STAFF_NPC_DRAMA_ROBOT","text":{"KOREA":"아야.","JPN":"いたっ。","ENG":"Ouch.","TWN":"哎呀。"},"stage":{"bg":"FALL_PARK","slots":{"L":{"char_id":"STAFF_NPC_DRAMA_ROBOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"컷! 컷!","JPN":"カット！　カット！","ENG":"Cut! Cut!","TWN":"Cut！Cut！"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"지금 뭐하는 거야?","JPN":"何やってんだ？","ENG":"What are you doing?","TWN":"你在幹什麼？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"왜요? 대본대로 했잖아요. <color=#ffd34c>분노를 참지 못한 파벨라가 로봇을 때린다.</color>","JPN":"何がですか？　台本どおりにやりましたよね。<color=#ffd34c>怒りに耐えられなかったファヴェーラがロボットを殴る…</color>","ENG":"What? I did as the script says. <color=#ffd34c>Fabella, unable to stop her rage, hits the robot.</color>","TWN":"怎麼了？我是照劇本演的啊？<color=#ffd34c>克制不住怒氣的帕貝拉打了機器人。</color>"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"그래서 고작 뺨을 때린 거야?","JPN":"それでビンタしたと？","ENG":"And all you do is slap his cheek?","TWN":"所以你就只打他一個巴掌？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"네가 파벨라라면 좀 더 주먹에 파워와 광기를 담아서 날려버려야지!","JPN":"ファヴェーラなんだったら、もっと拳にパワーと狂気を込めてぶっ飛ばせよ！","ENG":"If you really are Fabella, you’re supposed to fling him away with strength and madness!","TWN":"你演的帕貝拉應該要重重給他一拳才對！"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"지, 진짜로 때리라고요? 그런 건 적당히 CG처리 하면 되잖아요!","JPN":"ほ、本当に殴るんですか？　そんなのは適当にCG処理したらいいじゃないですか！","ENG":"What? Hit for real? You can just use CGI to make up that kind of stuff!","TWN":"你…你是說來真的？那個不是可以用CG處理嗎？！"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"STAFF_NPC_DRAMA_ROBOT","text":{"KOREA":"저는 걱정 마시고 마음껏 때리세요, 미스. 제 몸은 튼튼한 이터니움 합금으로 되어있으니까요.","JPN":"私のことは心配せずに思いきり殴ってください、ミス。私の体は頑丈なエタニウム合金でできていますから。","ENG":"No worries, Miss. Feel free to hit me. My body is sturdy as it consists of Eternium alloy.","TWN":"小姐，你不用擔心我，儘管打！我的身體是用堅硬的永恆之金合金打造而成的。"},"stage":{"bg":"FALL_PARK","slots":{"L":{"char_id":"STAFF_NPC_DRAMA_ROBOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"하? 누가 누굴 걱정해? 주먹으로 때렸다간 내 뼈가 먼저 나갈 거라고!","JPN":"はあ？　誰の心配をしてるの？　拳で殴ったら、私の骨が折れるじゃない！","ENG":"Huh? Who says I’m worried about you?! My hand will break if I punch you hard!","TWN":"蛤？誰有空擔心你？我是擔心我的手會打到骨折！"},"stage":{"bg":"FALL_PARK","slots":{"L":{"char_id":"STAFF_NPC_DRAMA_ROBOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_HATE"}}}}]`);export{e as default};